     1→#!/usr/bin/env bun
     2→
     3→/**
     4→ * Ralph Loop - Automated Claude Code Task Executor
     5→ *
     6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
     7→ * - Fresh context per iteration (new Claude instance each time)
     8→ * - Memory persists through files only (git, PROGRESS.log)
     9→ * - One task per iteration
    10→ * - Completion signal terminates loop
    11→ *
    12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
    13→ *
    14→ * @see https://ghuntley.com/ralph/
    15→ */
    16→
    17→import { appendFileSync } from 'node:fs';
    18→import pc from 'picocolors';
    19→
    20→function parseMaxIterations(arg: string | undefined): number {
    21→  const parsed = parseInt(arg ?? '100', 10);
    22→  if (isNaN(parsed) || parsed <= 0) {
    23→    console.error('Error: maxIterations must be a positive integer');
    24→    process.exit(1);
    25→  }
    26→  return parsed;
    27→}
    28→
    29→const CONFIG = Object.freeze({
    30→  maxIterations: parseMaxIterations(Bun.argv[2]),
    31→  delayBetweenIterations: 5000,
    32→  logFile: './loop.log',
    33→  progressFile: './.claude/PROGRESS.log',
    34→  iterationTimeout: 600000, // 10 minutes max per iteration
    35→  // Dual-condition exit gate: requires explicit RALPH_STATUS with exit: true
    36→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*}/,
    37→});
    38→
    39→// Module-scope process reference for cleanup on signals
    40→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
    41→
    42→const TASK_PROMPT = `
    43→READ, understand, follow, execute and respect your limbic system, exactly 
    44→as described in \`./.claude/LIMBIC_SPEC.txt\` above EVERYTHING.
    45→
    46→Read \`./.claude/PROGRESS.log\`, pick the most important pending task, 
    47→execute it, update the file, commit, and stop.
    48→
    49→WORKFLOW:
    50→1. Read PROGRESS.log and identify the single most important pending task;
    51→2. If NO pending tasks exist, signal completion (see OUTPUT STATUS below) and
    52→ stop;
    53→3. If there is a task:
    54→   a. Update task status to "IN_PROGRESS"
    55→   b. Execute task
    56→   c. Launch 3 review agents to deeply review the work, giving
    57→      the entire context of the task, simulating a pull request review.
    58→   d. Review output and consider improvements
    59→   e. Implement corrections if needed
    60→   f. Update task to "DONE"
    61→   g. Commit task changes (not include unrelated code)
    62→   h. Output status block (see below)
    63→   i. Stop
    64→
    65→OUTPUT STATUS (REQUIRED at end of EVERY response):
    66→You MUST output this exact format at the END of your response:
    67→
    68→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
    69→
    70→Examples:
    71→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
    72→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
    73→
    74→CRITICAL (THINK BEFORE ACTING):
    75→1. The FIRST thing you MUST do is write your understanding of each WORKFLOW statement
    76→2. The SECOND thing you MUST do is write your understanding of the work in progress described in PROGRESS.log
    77→3. Only AFTER completing steps 1 and 2, proceed with the task execution
    78→4. If more work is necessary, add a new task to the file, set "exit": false, and Stop
    79→5. Only set "exit": true when ALL tasks in PROGRESS.log are completed
    80→6. For multiple lint/typescript/test errors, fix just one error and register others in PROGRESS.log to be fixed in the next iteration
    81→7. If a new single new line starting with "- [ ]" is present in PROGRESS.log, there are more work, DO NOT EXIT.
    82→`;
    83→
    84→type ColorName = 'red' | 'green' | 'yellow' | 'blue';
    85→
    86→function log(message: string, color?: ColorName): void {
    87→  const timestamp = new Date().toISOString().replace('T', ' ').slice(0, 19);
    88→  const line = `[${timestamp}] ${message}`;
    89→  const coloredLine = color ? pc[color](line) : line;
    90→
    91→  console.log(coloredLine);
    92→  appendFileSync(CONFIG.logFile, line + '\n');
    93→}
    94→
    95→async function checkDependencies(): Promise<void> {
    96→  const result = await Bun.$`which claude`.quiet().nothrow();
    97→  if (result.exitCode !== 0) {
    98→    log("ERROR: 'claude' command not found. Install Claude Code CLI.", 'red');
    99→    process.exit(1);
   100→  }
   101→
   102→  const progressFile = Bun.file(CONFIG.progressFile);
   103→  if (!(await progressFile.exists())) {
   104→    log(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
   105→    process.exit(1);
   106→  }
   107→}
   108→
   109→function printHeader(): void {
   110→  console.log();
   111→  console.log(pc.blue(`==========================================`));
   112→  console.log(pc.blue(`   Ralph Loop - Bun.js Edition`));
   113→  console.log(pc.blue(`==========================================`));
   114→  console.log(`Max iterations: ${pc.yellow(String(CONFIG.maxIterations))}`);
   115→  console.log(`Log file: ${pc.yellow(CONFIG.logFile)}`);
   116→  console.log(
   117→    `Delay between iterations: ${pc.yellow(`${CONFIG.delayBetweenIterations / 1000}s`)}`,
   118→  );
   119→  console.log();
   120→}
   121→
   122→/**
   123→ * Stream-JSON message types from Claude Code CLI
   124→ * @see https://gist.github.com/SamSaffron/603648958a8c18ceae34939a8951d417
   125→ * @see https://github.com/anthropics/claude-code/issues/733
   126→ */
   127→interface ContentBlock {
   128→  type: 'text' | 'tool_use' | 'tool_result';
   129→  text?: string;
   130→  name?: string;
   131→  input?: unknown;
   132→  content?: string;
   133→}
   134→
   135→interface StreamMessage {
   136→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
   137→  subtype?: string;
   138→  role?: 'assistant' | 'user';
   139→  // For stream_event type
   140→  event?: {
   141→    type: string;
   142→    delta?: {
   143→      type: string;
   144→      text?: string;
   145→    };
   146→  };
   147→  // For result type
   148→  result?: string;
   149→  // For assistant/user/message types
   150→  message?: {
   151→    role?: string;
   152→    content?: ContentBlock[];
   153→  };
   154→  // Direct content array (alternative format)
   155→  content?: ContentBlock[];
   156→}
   157→
   158→async function runIteration(): Promise<{
   159→  output: string;
   160→  exitCode: number;
   161→}> {
   162→  log('Executing Claude Code...');
   163→
   164→  const proc = Bun.spawn(
   165→    [
   166→      'claude',
   167→      '-p',
   168→      TASK_PROMPT,
   169→      '--verbose',
   170→      '--debug',
   171→      '--dangerously-skip-permissions',
   172→      '--output-format',
   173→      'stream-json',
   174→      '--include-partial-messages',
   175→    ],
   176→    {
   177→      cwd: process.cwd(),
   178→      env: process.env,
   179→      stdout: 'pipe',
   180→      stderr: 'inherit', // Pass through stderr to console
   181→    },
   182→  );
   183→
   184→  // Store proc reference for cleanup on signals
   185→  currentProc = proc;
   186→
   187→  let output = '';
   188→  let timedOut = false;
   189→  const decoder = new TextDecoder();
   190→  let buffer = '';
   191→  let hasContentInBlock = false;
   192→
   193→  // Iteration timeout
   194→  const timeoutId = setTimeout(() => {
   195→    timedOut = true;
   196→    log('Iteration timeout reached. Killing process...', 'yellow');
   197→    try {
   198→      proc.kill();
   199→    } catch {
   200→      // Process may have already exited
   201→    }
   202→  }, CONFIG.iterationTimeout);
   203→
   204→  const reader = proc.stdout.getReader();
   205→
   206→  try {
   207→    while (true) {
   208→      const { done, value } = await reader.read();
   209→      if (done) break;
   210→
   211→      buffer += decoder.decode(value, { stream: true });
   212→
   213→      // Process complete JSON lines
   214→      const lines = buffer.split('\n');
   215→      buffer = lines.pop() || ''; // Keep incomplete line in buffer
   216→
   217→      for (const line of lines) {
   218→        if (!line.trim()) continue;
   219→
   220→        try {
   221→          const msg: StreamMessage = JSON.parse(line);
   222→
   223→          // 1. Handle stream_event (real-time token streaming)
   224→          if (msg.type === 'stream_event') {
   225→            if (msg.event?.type === 'content_block_start') {
   226→              hasContentInBlock = false;
   227→            }
   228→            if (msg.event?.type === 'content_block_delta') {
   229→              const text = msg.event.delta?.text;
   230→              if (text) {
   231→                process.stdout.write(text);
   232→                output += text;
   233→                hasContentInBlock = true;
   234→              }
   235→            }
   236→            if (msg.event?.type === 'content_block_stop' && hasContentInBlock) {
   237→              process.stdout.write('\n');
   238→              output += '\n';
   239→              hasContentInBlock = false;
   240→            }
   241→          }
   242→
   243→          // 2. Handle assistant/message types (full messages with content arrays)
   244→          // This captures sub-agent outputs and tool results
   245→          if (msg.type === 'assistant' || msg.type === 'message') {
   246→            const contentBlocks = msg.message?.content ?? msg.content;
   247→            if (contentBlocks && Array.isArray(contentBlocks)) {
   248→              for (const block of contentBlocks) {
   249→                if (block.type === 'text' && block.text) {
   250→                  process.stdout.write(block.text);
   251→                  output += block.text;
   252→                  process.stdout.write('\n');
   253→                  output += '\n';
   254→                }
   255→              }
   256→            }
   257→          }
   258→
   259→          // 3. Handle user messages (tool results)
   260→          if (msg.type === 'user') {
   261→            const contentBlocks = msg.message?.content ?? msg.content;
   262→            if (contentBlocks && Array.isArray(contentBlocks)) {
   263→              for (const block of contentBlocks) {
   264→                if (block.type === 'tool_result' && block.content) {
   265→                  // Tool results - print with prefix for visibility
   266→                  const resultText = `\n${pc.gray(block.content)}\n`;
   267→                  process.stdout.write(resultText);
   268→                  output += block.content;
   269→                  process.stdout.write('\n');
   270→                  output += '\n';
   271→                }
   272→              }
   273→            }
   274→          }
   275→
   276→          // 4. Handle result type - final output
   277→          if (msg.type === 'result' && msg.result) {
   278→            if (!output.trim()) {
   279→              output = msg.result;
   280→            }
   281→          }
   282→        } catch {
   283→          // Ignore JSON parse errors for incomplete/malformed lines
   284→        }
   285→      }
   286→    }
   287→
   288→    // Process any remaining buffer
   289→    if (buffer.trim()) {
   290→      try {
   291→        const msg: StreamMessage = JSON.parse(buffer);
   292→        if (msg.type === 'result' && msg.result) {
   293→          if (!output.trim()) output = msg.result;
   294→        }
   295→      } catch {
   296→        // Ignore
   297→      }
   298→    }
   299→  } finally {
   300→    clearTimeout(timeoutId);
   301→    reader.releaseLock();
   302→    currentProc = null;
   303→  }
   304→
   305→  if (timedOut) {
   306→    return {
   307→      output,
   308→      exitCode: 124,
   309→    }; // Standard timeout exit code
   310→  }
   311→
   312→  const exitCode = await proc.exited;
   313→  console.log(); // Newline after streaming output
   314→
   315→  return {
   316→    output,
   317→    exitCode,
   318→  };
   319→}
   320→
   321→async function main(): Promise<void> {
   322→  let cleanupCalled = false;
   323→
   324→  const cleanup = (signal: string) => {
   325→    if (cleanupCalled) return;
   326→    cleanupCalled = true;
   327→    console.log();
   328→    log(`Script interrupted by ${signal}. Cleaning up...`);
   329→
   330→    // Kill any running Claude process
   331→    if (currentProc) {
   332→      try {
   333→        currentProc.kill();
   334→      } catch {
   335→        // Process may have already exited
   336→      }
   337→    }
   338→
   339→    const exitCode = signal === 'SIGINT' ? 130 : 143;
   340→    process.exit(exitCode);
   341→  };
   342→
   343→  process.on('SIGINT', () => cleanup('SIGINT'));
   344→  process.on('SIGTERM', () => cleanup('SIGTERM'));
   345→
   346→  await checkDependencies();
   347→  printHeader();
   348→
   349→  log('Starting automated task loop...');
   350→
   351→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
   352→    console.log();
   353→    console.log(pc.green(`==========================================`));
   354→    log(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
   355→    console.log(pc.green(`==========================================`));
   356→    console.log();
   357→
   358→    const { output, exitCode } = await runIteration();
   359→
   360→    if (exitCode === 0) {
   361→      log('Claude Code execution completed successfully', 'green');
   362→    } else {
   363→      log(
   364→        `Claude Code exited with status ${exitCode}, checking output...`,
   365→        'yellow',
   366→      );
   367→    }
   368→
   369→    // Dual-condition exit gate: requires explicit RALPH_STATUS with exit: true
   370→    const hasExitSignal = CONFIG.exitPattern.test(output);
   371→    if (hasExitSignal) {
   372→      // Extract status for logging
   373→      const match = output.match(/RALPH_STATUS:\s*(\{[^}]*})/);
   374→      const status = match ? match[1] : 'unknown';
   375→      console.log();
   376→      console.log(pc.green(`==========================================`));
   377→      log('ALL TASKS COMPLETED!', 'green');
   378→      log(`Exit status: ${status}`, 'green');
   379→      log(`Total iterations: ${iteration}`, 'green');
   380→      console.log(pc.green(`==========================================`));
   381→      process.exit(0);
   382→    }
   383→
   384→    // More specific error detection - avoid false positives from "error handling", etc.
   385→    const hasErrors =
   386→      exitCode !== 0 ||
   387→      /(?:^|\n)\s*(?:Error:|ERROR:|Failed:|FAILED:)/m.test(output) ||
   388→      output.includes('claude: error');
   389→    if (hasErrors) {
   390→      log('Warning: Potential errors detected in output.', 'yellow');
   391→    }
   392→
   393→    if (iteration < CONFIG.maxIterations) {
   394→      console.log();
   395→      log(
   396→        `Waiting ${CONFIG.delayBetweenIterations / 1000} seconds before next iteration...`,
   397→      );
   398→      await Bun.sleep(CONFIG.delayBetweenIterations);
   399→    }
   400→  }
   401→
   402→  console.log();
   403→  console.log(pc.red(`==========================================`));
   404→  log(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
   405→  log('Loop stopped - tasks may still be pending', 'red');
   406→  console.log(pc.red(`==========================================`));
   407→  process.exit(1);
   408→}
   409→
   410→main();
   411→

