import pc from 'picocolors';

// Test basic colors
console.log('Testing picocolors API:');
console.log('red:', pc.red('test'));
console.log('green:', pc.green('test'));
console.log('yellow:', pc.yellow('test'));
console.log('blue:', pc.blue('test'));
console.log('gray:', pc.gray('test'));

// Test with numbers (should fail or convert)
console.log('\\nTesting numeric input:');
try {
  console.log('yellow(42):', pc.yellow(42));
} catch (e) {
  console.log('Error with number:', e.message);
}

// Test with undefined/null
console.log('\\nTesting undefined/null:');
try {
  console.log('yellow(undefined):', pc.yellow(undefined));
} catch (e) {
  console.log('Error with undefined:', e.message);
}

// Test dynamic access
console.log('\\nTesting dynamic property access:');
const colorName = 'red';
console.log('pc[colorName](test):', pc[colorName]('test'));

// Check if blackBright exists
console.log('\\nChecking blackBright:');
console.log('pc.blackBright exists:', typeof pc.blackBright);

// Check available properties
console.log('\\nAll picocolors properties:');
console.log(Object.keys(pc).sort().join(', '));
"

